  group_by(year) |&gt;
  filter(n() &gt;= 30) |&gt;
  ungroup() |&gt;
  nest(data = -year) |&gt;
  mutate(
    model = map(
      data,
      \(data) lm(
        Re ~ lagged_BEME,
        data = data
      )
    ),
    coefficients = map(
      model,
      broom::tidy
    ),
    fit = map(
      model,
      broom::glance
    )
  )

