4.5 補助関数

median_safe &lt;- function(x) {
  values &lt;- x[is.finite(x)]

  if (length(values) == 0) {
    return(NA_real_)
  }

  median(values)
}

mean_safe &lt;- function(x) {
  values &lt;- x[is.finite(x)]

  if (length(values) == 0) {
    return(NA_real_)
  }

  mean(values)
}

weighted_mean_safe &lt;- function(x, weight) {
  valid &lt;- is.finite(x) &
    is.finite(weight) &
    weight &gt; 0

  if (!any(valid)) {
    return(NA_real_)
  }

  sum(x[valid] * weight[valid]) /
    sum(weight[valid])
}

significance_stars &lt;- function(p_value) {
  case_when(
    is.na(p_value) ~ "",
    p_value &lt; 0.01 ~ "***",
    p_value &lt; 0.05 ~ "**",
    p_value &lt; 0.10 ~ "*",
    TRUE ~ ""
  )
}

