4.7 市場ポートフォリオ
年度 \(t\) の企業 \(i\) の市場ポートフォリオ・ウェイト \(w^M_{i,t}\) は、前年度末時価総額から計算する。
\[
w^M_{i,t}
=
\frac{ME_{i,t-1}}
{\sum_j ME_{j,t-1}}
\]

market_membership &lt;- annual_data |&gt;
  filter(
    is.finite(lagged_ME),
    lagged_ME &gt; 0
  ) |&gt;
  group_by(year) |&gt;
  mutate(
    market_weight = lagged_ME /
      sum(lagged_ME)
  ) |&gt;
  ungroup() |&gt;
  select(
    year,
    firm_ID,
    lagged_ME,
    market_weight
  )

market_membership


market_weight_check &lt;- market_membership |&gt;
  group_by(year) |&gt;
  summarise(
    firms = n_distinct(firm_ID),
    weight_sum = sum(market_weight),
    minimum_weight = min(market_weight),
    maximum_weight = max(market_weight),
    .groups = "drop"
  )

