      is.finite(R) &
        is.finite(lagged_ME) &
        lagged_ME &gt; 0
    ),
    .groups = "drop"
  ) |&gt;
  mutate(
    R_Me = R_M - R_F,
    return_coverage = valid_return_firms /
      eligible_firms
